SELECT DISTINCT u.user_id, u.dept_id, u.user_name, u.nick_name, u.email, u.phonenumber, u.sex, u.avatar, u.password, u.status, u.login_ip, u.login_date, u.create_by, u.create_time, u.update_by, u.update_time, u.remark, u.is_deleted FROM sys_user u INNER JOIN sys_user_role ur ON u.user_id = ur.user_id
ur.role_id = #{roleId} AND u.is_deleted = 0
AND ${ew.sqlSegment}

SELECT DISTINCT u.user_id, u.dept_id, u.user_name, u.nick_name, u.email, u.phonenumber, u.sex, u.avatar, u.password, u.status, u.login_ip, u.login_date, u.create_by, u.create_time, u.update_by, u.update_time, u.remark, u.is_deleted FROM sys_user u
u.is_deleted = 0 AND NOT EXISTS (SELECT 1 FROM sys_user_role ur WHERE ur.user_id = u.user_id AND ur.role_id = #{roleId})
AND ${ew.sqlSegment}
